// C# — Selection Sort
int[] arr = { 64, 25, 12, 22, 11 };
int n = arr.Length;

for (int i = 0; i < n - 1; i++)
{
    // find the index of the minimum element in the unsorted portion
    int minIndex = i;
    for (int j = i + 1; j < n; j++)
    {
        if (arr[j] < arr[minIndex])
            minIndex = j;
    }

    // swap minimum with the first unsorted element
    if (minIndex != i)
    {
        int temp = arr[minIndex];
        arr[minIndex] = arr[i];
        arr[i] = temp;
    }
}
// arr = { 11, 12, 22, 25, 64 }

